#include<bits/stdc++.h>
using namespace std;
int r[1010][1010],d[1010][1010],a[1010][1010],n,m,c,f;
int sumu[1010][1010];
const long long mod=998244353;
int main()
{
    int t,id;
    scanf("%d%d",&t,&id);
    while(t--)
    {
        if(id==1)
        {
            printf("0 0\n");
            continue;
        }
        scanf("%d%d%d%d",&n,&m,&c,&f);
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=m;j++)
            {
                char ch;
                cin>>ch;
                a[i][j]=ch-'0';
            }
        }
        memset(r,0,sizeof(r));
        memset(d,0,sizeof(d));
        for(int i=n;i>=1;i--)
        {
            for(int j=m;j>=1;j--)
            {
                if(a[i][j]==1)
                {
                    r[i][j]=d[i][j]=0;
                }
                else
                {
                    r[i][j]=r[i][j+1]+1;
                    d[i][j]=d[i+1][j]+1;
                }
            }
        }
        for(int i=1;i<=n;i++)
        {
        	for(int j=1;j<=m;j++)
        	{
        		if(a[i][j]==0)
        		{
        			sumu[i][j]=sumu[i-1][j]+(r[i][j]-1);
				}
				else
				{
					sumu[i][j]=0;
				}
			}
		}
        long long ansc=0,ansf=0;
        for(int k=3;k<=n;k++)
        {
	        for(int j=1;j<=m;j++)
	        {
	            if(a[k][j]==1||a[k-1][j]==1)
	            {
	                continue;
	            }
                if(r[k][j]>=2)
                {
                    int tmp=sumu[k-2][j]*(r[k][j]-1)%mod;
                    ansc+=tmp;
                    if(k!=n&&d[k][j]>=2)
                    {
                        tmp=sumu[k-2][j]*(r[k][j]-1)%mod*(d[k][j]-1)%mod;
                        ansf+=tmp;
                        ansf%=mod;
                    }
                    ansc%=mod;
                }
	        }
		}
        printf("%lld %lld\n",ansc*c%mod,ansf*f%mod);
    }
    return 0;
}
